class Solution {
    public int lengthAfterTransformations(String s, int t, List<Integer> nums) {
        int mod = 1000000007;
        int n = s.length();
        int[] count = new int[26];
        for (char c : s.toCharArray()) {
            count[c - 'a']++;
        }
        for (int i = 0; i < t; i++) {
            int[] nextCount = new int[26];
            for (int j = 0; j < 26; j++) {
                int k = (j + nums[j]) % 26;
                nextCount[k] += count[j];
                nextCount[k] %= mod;
            }
            count = nextCount;
        }
        int result = 0;
        for (int i = 0; i < 26; i++) {
            result = (result + count[i]) % mod;
        }
        return result;
    }
}
